import React from 'react'
import { IoIosFlash } from "react-icons/io";
import { TSubTitle } from '../../Layout/app/Types';

const SubTitle = ({title,href,count}:TSubTitle) => {
  return (
    <div className='SubTitle'>
        <div>
        <IoIosFlash />
           {title} 
        </div>
        <div>
            <a href='/'>
            See more{count}
            </a>
        </div>

    </div>
  )
}

export default SubTitle
